arguments.command:
@'
$ErrorActionPreference='Stop'
Get-ChildItem 'scenarios' -Directory | Sort-Object Name | ForEach-Object {
  $scenario=$_.Name; $path=Join-Path $_.FullName 'docs\DECISIONS.md'; $lines=Get-Content $path
  $entries=@(); $cur=$null
  foreach($line in $lines){
    if($line -match '^##\s+(ADR-\d+):\s*(.+?)\s*$'){
      if($null -ne $cur){$entries += [pscustomobject]$cur}
      $id=$Matches[1]; $title=$Matches[2]
      $anchor=('#'+($id+'-'+$title).ToLowerInvariant().Replace(' ','-'))
      $cur=[ordered]@{id=$id;title=$title;governance_state=$null;replaces_ids=@();replaced_by_id=$null;body_anchor=$anchor;_replace_lines=@();_replaced_lines=@()}
    } elseif($null -ne $cur -and $line -match '^- 治理状态：(.*)$'){$cur.governance_state=$Matches[1].Trim()
    } elseif($null -ne $cur -and $line -match '^- 替代关系：replaces\s+(.+)$'){
      $ids=@($Matches[1] -split '\s*,\s*'); $cur.replaces_ids += $ids; $cur._replace_lines += ,$ids
    } elseif($null -ne $cur -and $line -match '^- 替代关系：replaced-by\s+(ADR-\d+)\s*$'){$cur._replaced_lines += $Matches[1]; if($null -eq $cur.replaced_by_id){$cur.replaced_by_id=$Matches[1]}}
  }
  if($null -ne $cur){$entries += [pscustomobject]$cur}
  [pscustomobject]@{scenario=$scenario;projection=@($entries | ForEach-Object {[pscustomobject]@{id=$_.id;title=$_.title;governance_state=$_.governance_state;replaces_ids=$_.replaces_ids;replaced_by_id=$_.replaced_by_id;body_anchor=$_.body_anchor}})} | ConvertTo-Json -Depth 6 -Compress
}
